static void findRangeK_parallel(long height,
			knode *knodes,
			long knodes_elem,
			long *currKnode,
			long *offset,
			long *lastKnode,
			long *offset_2,
			int *start,
			int *end,
			int *recstart, 
			int *reclength,
			int count,
			int order)
{
	int threadsPerBlock = order < 1024 ? order : 1024;

	#pragma omp parallel num_threads(count)
	{
		int bid = omp_get_thread_num();
		int thid;

		long local_currKnode = currKnode[bid];
		long local_lastKnode = lastKnode[bid];
		long local_offset = offset[bid];
		long local_offset_2 = offset_2[bid];

		int local_start = start[bid];
		int local_end = end[bid];

		for(int i = 0; i < height; i++){
			for(thid = 0; thid < threadsPerBlock; thid++){
				if(thid < knodes[local_currKnode].num_keys + 1) {
					int key_val = knodes[local_currKnode].keys[thid];
					int next_key_val = (thid + 1 < knodes[local_currKnode].num_keys + 1) ? knodes[local_currKnode].keys[thid+1] : 2147483647;

					if(key_val <= local_start && next_key_val > local_start){
						if(knodes[local_currKnode].indices[thid] < knodes_elem){
							local_offset = knodes[local_currKnode].indices[thid];
						}
					}
				}

				if(thid < knodes[local_lastKnode].num_keys + 1) {
					int key_val = knodes[local_lastKnode].keys[thid];
					int next_key_val = (thid + 1 < knodes[local_lastKnode].num_keys + 1) ? knodes[local_lastKnode].keys[thid+1] : 2147483647;

					if(key_val <= local_end && next_key_val > local_end){
						if(knodes[local_lastKnode].indices[thid] < knodes_elem){
							local_offset_2 = knodes[local_lastKnode].indices[thid];
						}
					}
				}
			}
			local_currKnode = local_offset;
			local_lastKnode = local_offset_2;
		}

		for(thid = 0; thid < threadsPerBlock; thid++){
			if(thid < knodes[local_currKnode].num_keys + 1) {
				if(knodes[local_currKnode].keys[thid] == local_start){
					recstart[bid] = knodes[local_currKnode].indices[thid];
				}
			}
		}

		for(thid = 0; thid < threadsPerBlock; thid++){
			if(thid < knodes[local_lastKnode].num_keys + 1) {
				if(knodes[local_lastKnode].keys[thid] == local_end){
					reclength[bid] = knodes[local_lastKnode].indices[thid] - recstart[bid] + 1;
				}
			}
		}
	}
}

